    39→          metadata_it != filter_metadata.end()) {
    40→        (*metadata_context.mutable_filter_metadata())[metadata_it->first] = metadata_it->second;
    41→        break;
    42→      }
    43→    }
    44→  }
    45→
    46→  for (const auto& context_key : typed_metadata_context_namespaces) {
    47→    for (const MetadataProto* metadata : source_metadata) {
    48→      if (metadata == nullptr) {
