    38→bool HeaderUtility::matchHeaders(const HeaderMap& request_headers,
    39→                                 const std::vector<HeaderDataPtr>& config_headers) {
    40→  // No headers to match is considered a match.
    41→  if (!config_headers.empty()) {
    42→    for (const HeaderDataPtr& cfg_header_data : config_headers) {
    43→      if (!cfg_header_data->matchesHeaders(request_headers)) {
    44→        return false;
    45→      }
    46→    }
    47→  }
    48→
    49→  return true;
    50→}
