    89→HeaderUtility::HeaderDataPtr
    90→HeaderUtility::createHeaderData(const envoy::config::route::v3::HeaderMatcher& config,
    91→                                Server::Configuration::CommonFactoryContext& factory_context) {
    92→  switch (config.header_match_specifier_case()) {
    93→  case envoy::config::route::v3::HeaderMatcher::HeaderMatchSpecifierCase::kExactMatch:
    94→    return std::make_unique<HeaderDataExactMatch>(config);
    95→    break;
    96→  case envoy::config::route::v3::HeaderMatcher::HeaderMatchSpecifierCase::kSafeRegexMatch:
    97→    return THROW_OR_RETURN_VALUE(HeaderDataRegexMatch::create(config, factory_context),
    98→                                 std::unique_ptr<HeaderDataRegexMatch>);
    99→    break;
   100→  case envoy::config::route::v3::HeaderMatcher::HeaderMatchSpecifierCase::kRangeMatch:
   101→    return std::make_unique<HeaderDataRangeMatch>(config);
   102→    break;
   103→  case envoy::config::route::v3::HeaderMatcher::HeaderMatchSpecifierCase::kPresentMatch:
   104→    return std::make_unique<HeaderDataPresentMatch>(config);
   105→    break;
   106→  case envoy::config::route::v3::HeaderMatcher::HeaderMatchSpecifierCase::kPrefixMatch:
   107→    return std::make_unique<HeaderDataPrefixMatch>(config);
   108→    break;
   109→  case envoy::config::route::v3::HeaderMatcher::HeaderMatchSpecifierCase::kSuffixMatch:
   110→    return std::make_unique<HeaderDataSuffixMatch>(config);
   111→    break;
   112→  case envoy::config::route::v3::HeaderMatcher::HeaderMatchSpecifierCase::kContainsMatch:
   113→    return std::make_unique<HeaderDataContainsMatch>(config);
   114→    break;
   115→  case envoy::config::route::v3::HeaderMatcher::HeaderMatchSpecifierCase::kStringMatch:
   116→    return std::make_unique<HeaderDataStringMatch>(config, factory_context);
   117→    break;
   118→  case envoy::config::route::v3::HeaderMatcher::HeaderMatchSpecifierCase::
   119→      HEADER_MATCH_SPECIFIER_NOT_SET:
   120→    FALLTHRU;
   121→  default:
   122→    return std::make_unique<HeaderDataPresentMatch>(config, true);
   123→    break;
   124→  }
   125→}
