   334→bool HeaderUtility::isCapsuleProtocol(const RequestOrResponseHeaderMap& headers) {
   335→  Http::HeaderMap::GetResult capsule_protocol =
   336→      headers.get(Envoy::Http::LowerCaseString("Capsule-Protocol"));
   337→  // When there are multiple Capsule-Protocol header entries, it returns false. RFC 9297 specifies
   338→  // that non-boolean value types must be ignored. If there are multiple header entries, the value
   339→  // type becomes a List so the header field must be ignored.
   340→  if (capsule_protocol.size() != 1) {
   341→    return false;
   342→  }
   343→  // Parses the header value and extracts the boolean value ignoring parameters.
   344→  absl::optional<quiche::structured_headers::ParameterizedItem> header_item =
   345→      quiche::structured_headers::ParseItem(capsule_protocol[0]->value().getStringView());
   346→  return header_item && header_item->item.is_boolean() && header_item->item.GetBoolean();
   347→}
