   611→HeaderUtility::HeaderValidationResult
   612→HeaderUtility::validateContentLength(absl::string_view header_value,
   613→                                     bool override_stream_error_on_invalid_http_message,
   614→                                     bool& should_close_connection, size_t& content_length_output) {
   615→  should_close_connection = false;
   616→  std::vector<absl::string_view> values = absl::StrSplit(header_value, ',');
   617→  absl::optional<uint64_t> content_length;
